"const sleep = ms => new Promise(r => setTimeout(r, ms));

const osrmRouteCache = {};
const mapCarPalette = [
  '#3b82f6', // Blue
  '#10b981', // Emerald
  '#f59e0b', // Amber
  '#8b5cf6', // Violet
  '#ec4899', // Pink
  '#14b8a6', // Teal
  '#6366f1', // Indigo
  '#f97316', // Orange
  '#84cc16', // Lime
  '#06b6d4', // Cyan
];

function getCarColor(carId) {
  let hash = 0;
  const str = String(carId);
  for (let i = 0; i < str.length; i++) {
    hash = str.charCodeAt(i) + ((hash << 5) - hash);
  }
  return mapCarPalette[Math.abs(hash) % mapCarPalette.length];
}

async function fetchOSRMRoute(startCoords, endCoords) {
  const key = `${startCoords[0].toFixed(5)},${startCoords[1].toFixed(5)};${endCoords[0].toFixed(5)},${endCoords[1].toFixed(5)}`;
  if (osrmRouteCache[key]) return osrmRouteCache[key];

  try {
    const url = `https://router.project-osrm.org/route/v1/driving/${startCoords[1]},${startCoords[0]};${endCoords[1]},${endCoords[0]}?overview=full&geometries=geojson`;
    const res = await fetch(url);
    const data = await res.json();
    if (data.routes && data.routes.length > 0) {
      const coords = data.routes[0].geometry.coordinates.map(c => [c[1], c[0]]);
      osrmRouteCache[key] = coords;
      return coords;
    }
  } catch (e) {
    console.error("OSRM error:", e);
  }
  return [startCoords, endCoords];
}"

